def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    std_dev = np.sqrt(variance)
    max_capacity = np.max(bins) if bins.size > 0 else 1
    min_capacity = np.min(positive_bins) if positive_bins.size > 0 else 0.1
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        if ratio == 1:
            base_score = 0.0
        elif ratio > 0.9:
            base_score = ((1 - ratio) ** 8) * 1.5 + 0.3
        elif ratio > 0.7:
            base_score = np.exp(-ratio * 12) + 0.1
        elif ratio > 0.4:
            base_score = sum([((-1)**(k+1)) * (ratio**(k+3)) / (k*1.05) for k in range(1, 12)])
            base_score = abs(base_score) + 0.12
        else:
            base_score = sum([((-1)**k) * (ratio**(k+2)) / (k ** 1.4) for k in range(1, 15)])
            base_score = abs(base_score) + 0.13
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity <= 0:
                    continue
                diff = abs(capacity - neighbor_capacity)
                norm_diff = diff / max(capacity, neighbor_capacity)
                weight = 1 / (offset ** 2.5)
                influence = norm_diff * weight
                if neighbor_capacity > avg_capacity + 1.5 * std_dev:
                    influence *= 1.2
                elif neighbor_capacity < avg_capacity - 1.5 * std_dev:
                    influence *= 0.85
                neighbors_influence += influence
                neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.65) + (avg_capacity ** 0.35)
        cap_factor *= (1 + (variance / (capacity + 0.01)))
        penalty = 0.0
        if capacity < item:
            penalty = ((item - capacity) ** 3.5) * 0.45
        elif capacity > item * 2.5:
            penalty = 0.1 * (1 + (capacity - item*2.5)/max_capacity)
        if i % 5 == 0:
            base_score *= 0.75
            neighbors_influence *= 1.3
            penalty *= 1.2
        elif i % 3 == 0:
            base_score *= 1.05
            neighbors_influence *= 0.85
        elif i % 7 == 0:
            base_score *= 0.9
            neighbors_influence *= 1.1
        if i > 0 and abs(bins[i] - bins[i-1]) < std_dev / 2:
            base_score *= 0.9
            penalty *= 0.9
        if abs(capacity - avg_capacity) < std_dev:
            penalty *= 0.85
        smooth_factor = 1.0
        for j in range(max(0, i - 3), min(n, i + 4)):
            if j == i:
                continue
            diff = abs(capacity - bins[j])
            smooth_factor += np.exp(-diff / (avg_capacity + 0.01)) / (abs(i - j) + 1)
        priority = base_score + neighbors_influence / cap_factor + penalty
        priority /= smooth_factor
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 8
    return priorities
